#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        if (X >= Y) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

