#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); y = int(data[idx+1]); idx += 2
        out.append('YES' if x >= y else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

